// // This module controls the power gating signal based on the enable, power_gate_control, and sensor_input signals. The power gate signal is active when any of the inputs is low.
module power_gating_controller(
    input enable,
    input power_gate_control,
    input sensor_input,
    output power_gate_signal
);
    assign power_gate_signal = enable & power_gate_control & sensor_input;
endmodule
